type Rect struct {
    Width, Height float64
}
func (r Rect) Area() float64 {
    return r.Width * r.Height
}
r := Rect{3, 4}
fmt.Println(r.Area())

type Counter struct { n int }
func (c *Counter) Inc() { c.n++ }
c := Counter{0}
c.Inc()
c.Inc()
fmt.Println(c.n)
